390	/// Inserts the variable at `level` into the to-be-closed (`tbc`) list.
391	///
392	/// If the value is falsy (nil or false) it does not need closing and the
393	/// function returns immediately. Otherwise it verifies that the value has a
394	/// `__close` metamethod, then records it in `state.tbclist`.
395	///
396	/// C: `void luaF_newtbcupval(lua_State *L, StkId level)`
397	pub(crate) fn new_tbc_upval(state: &mut LuaState, level: StackIdx) -> Result<(), LuaError> {
398	    // C: lua_assert(level > L->tbclist.p);
399	    // In Rust: tbclist is Vec<StackIdx>, "current head" = last element.
400	    debug_assert!(
401	        state.tbclist.last().map_or(true, |&top| level.0 > top.0),
402	        "new tbc entry must be above current tbclist head"
403	    );
404	    // C: if (l_isfalse(s2v(level))) return;
405	    // macros.tsv: l_isfalse → matches!(o, LuaValue::Nil | LuaValue::Bool(false))
406	    // Clone before borrow to avoid aliasing with later mutable calls.
407	    let val = state.get_stack_value(level).clone();
408	    if matches!(val, LuaValue::Nil | LuaValue::Bool(false)) {
409	        return Ok(());
410	    }
411	    // C: checkclosemth(L, level);
412	    check_close_mth(state, level)?;
413	    // C: The original delta-encoding loop:
414	    //   while (cast_uint(level - L->tbclist.p) > MAXDELTA) {
415	    //     L->tbclist.p += MAXDELTA;
416	    //     L->tbclist.p->tbclist.delta = 0;  /* dummy node */
417	    //   }
418	    //   level->tbclist.delta = cast(unsigned short, level - L->tbclist.p);
419	    //   L->tbclist.p = level;
420	    //
421	    // PORT NOTE: The MAXDELTA / dummy-node mechanism is a C-only optimisation
422	    // required because `StackValue.tbclist.delta` is a `u16` (max 65535). With
423	    // `Vec<StackIdx>` the index fits a u32 and no dummy nodes are ever needed.
424	    state.tbclist.push(level);
425	    Ok(())
426	}
