428	/// Removes the given open upvalue from `state.openupval`.
429	///
430	/// The C version manipulates intrusive doubly-linked list pointers in O(1). In
431	/// Rust we use `Vec::retain` which is O(n) but correct. Phase B can optimise
432	/// this if profiling identifies it as hot.
433	///
434	/// C: `void luaF_unlinkupval(UpVal *uv)` — signature extended with `state`.
435	///
436	/// PORT NOTE: The original C signature takes only `UpVal *uv` (no `lua_State *`
437	/// needed for intrusive-list surgery). In Rust, state is required to find and
438	/// remove from the Vec. The public signature is intentionally extended.
439	pub(crate) fn unlink_upval(state: &mut LuaState, uv: &GcRef<UpVal>) {
440	    // C: lua_assert(upisopen(uv));
441	    // macros.tsv: upisopen → matches!(uv, UpVal::Open { .. })
442	    debug_assert!(
443	        uv.is_open(),
444	        "unlink_upval called on a closed upvalue"
445	    );
446	    // C: *uv->u.open.previous = uv->u.open.next;
447	    //    if (uv->u.open.next) uv->u.open.next->u.open.previous = uv->u.open.previous;
448	    //
449	    // In Rust: find by pointer identity (Rc::ptr_eq) and remove.
450	    // PERF(port): O(n) retain vs O(1) intrusive unlink — profile in Phase B.
451	    state.openupval.retain(|candidate| !GcRef::ptr_eq(candidate, uv));
452	}
